INSERT INTO articles (tour_id, title, content, image_url) VALUES
(1, 'Kinh nghiệm đi Đà Nẵng', 'Đà Nẵng là thành phố biển tuyệt đẹp với nhiều điểm tham quan nổi tiếng như Bà Nà Hills, Cầu Vàng và Phố Cổ Hội An gần đó. Thời tiết Đà Nẵng đẹp nhất vào mùa hè từ tháng 5 đến tháng 8.', 'https://images.unsplash.com/photo-1559592413-7cec4d0cae2b?auto=format&fit=crop&w=1200&q=80'),
(2, 'Khám phá Phú Quốc', 'Phú Quốc - hòn đảo ngọc của Việt Nam với bãi biển trong xanh và hải sản tươi ngon. Đừng bỏ qua chuyến cáp treo vượt biển dài nhất thế giới!', 'https://images.unsplash.com/photo-1573715806542-7a0ed6f4a4e6?auto=format&fit=crop&w=1200&q=80'),
(NULL, 'Cẩm nang du lịch Việt Nam 2026', 'Hướng dẫn toàn diện cho du khách khi khám phá Việt Nam. Từ ẩm thực đường phố đến các điểm check-in nổi tiếng, bài viết này sẽ giúp bạn lên kế hoạch chuyến đi hoàn hảo.', 'https://images.unsplash.com/photo-1506905925346-21bda4d32df4?auto=format&fit=crop&w=1200&q=80');
